41	const PROCESSING_FEE = 5;
42	const BLOCK_SIZE = 3;
43	const COMPONENT_UNIT_PREMIUM = 25;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const FIRST_INSURANCE_RATE = 0.1;
46	const LOYALTY_RATE = 0.2;
47	const LOYALTY_MIN_YEARS = 2;
48	const FOLLOW_UP_RATE = 0.15;
49	const CURSE_SURCHARGE_RATE = 0.5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	const HIGH_ENCHANTMENT_THRESHOLD = 5;
52	const DEDUCTIBLE = 100;
53	
54	const COMPONENT_TYPES = ["rune", "moonstone"];
55	
56	const BASE_PREMIUMS: Record<string, number> = {
57	  sword: 100,
58	  amulet: 60,
59	  staff: 80,
60	  potion: 40,
61	  rune: COMPONENT_UNIT_PREMIUM,
62	  moonstone: COMPONENT_UNIT_PREMIUM,
63	};
64	
65	const isComponent = (item: Item): boolean =>
66	  COMPONENT_TYPES.includes(item.type);
67	
68	const isMainItem = (item: Item): boolean => !isComponent(item);
69	
70	const unitPriceFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
71	
72	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
73	  items.reduce((sum, item) => sum + valueOf(item), 0);
74	
75	const componentGroupPremium = (count: number): number =>
76	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
77	
78	const countByType = (items: Item[]): Map<string, number> =>
79	  items.reduce((counts, item) => {
80	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
81	    return counts;
82	  }, new Map<string, number>());
83	
84	const componentsBasePremium = (items: Item[]): number =>
85	  [...countByType(items.filter(isComponent)).values()].reduce(
86	    (sum, count) => sum + componentGroupPremium(count),
87	    0
88	  );
89	
90	const mainItemsBasePremium = (items: Item[]): number =>
91	  sumOver(items.filter(isMainItem), unitPriceFor);
92	
93	const totalBasePremium = (items: Item[]): number =>
94	  mainItemsBasePremium(items) + componentsBasePremium(items);
95	
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const itemSurchargeRate = (item: Item): number =>
100	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
101	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
102	
103	const itemSurcharges = (item: Item): number =>
104	  unitPriceFor(item) * itemSurchargeRate(item);
105	
106	const totalSurcharges = (items: Item[]): number =>
107	  sumOver(items, itemSurcharges);
108	
109	const firstInsuranceSurcharge = (policyBase: number): number =>
110	  policyBase * FIRST_INSURANCE_RATE;
111	
112	const isLoyal = (customer: Customer): boolean =>
113	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
114	
115	const policyBaseShareWhen = (
116	  policyBase: number,
117	  applies: boolean,
118	  rate: number
119	): number => (applies ? policyBase * rate : 0);
120	
121	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
122	  policyBaseShareWhen(policyBase, isLoyal(customer), LOYALTY_RATE);
123	
124	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
125	  policyBaseShareWhen(policyBase, isFollowUp, FOLLOW_UP_RATE);
126	
127	const policyWideAdjustment = (
128	  policyBase: number,
129	  customer: Customer,
130	  isFollowUp: boolean
131	): number =>
132	  firstInsuranceSurcharge(policyBase) -
133	  loyaltyDiscount(policyBase, customer) -
134	  followUpDiscount(policyBase, isFollowUp);
135	
136	const roundPremiumInMHPCOsFavor = (premium: number): number =>
137	  Math.ceil(premium);
138	
139	export const quote = (input: QuoteInput, context: QuoteContext = {}): number => {
140	  const policyBase = totalBasePremium(input.items);
141	  const premiumBeforeFee =
142	    policyBase +
143	    totalSurcharges(input.items) +
144	    policyWideAdjustment(policyBase, input.customer, context.isFollowUp ?? false);
145	  return roundPremiumInMHPCOsFavor(premiumBeforeFee + PROCESSING_FEE);
146	};
147	
148	const damagePayout = (damage: Damage): number =>
149	  Math.max(0, damage.amount - DEDUCTIBLE);
150	
151	export const claim = (policy: Policy, incident: Incident): ClaimResult => {
152	  const payout = incident.damages.reduce(
153	    (sum, damage) => sum + damagePayout(damage),
154	    0
155	  );
156	  return { payout, remainingCap: policy.remainingCap - payout };
157	};
